"""Emission compliance tests for mcp_server (auto-generated by pact)."""

from mcp_server.mcp_server import McpServer


class TestEmissionCompliance:
    """Verify mcp_server emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_create_server_emits_events(self):
        """Method create_server emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = McpServer(event_handler=handler)
        try:
            obj.create_server()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for create_server'
        assert len(completed) >= 1, 'No completed/error event for create_server'
        assert invoked[0].get("pact_key") == "PACT:mcp_server:create_server"
        assert isinstance(invoked[0].get("input_classification"), list)

