    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = McpServer(event_handler=handler)
        try:
            obj.create_server()
        except (TypeError, Exception):
            pass
        try:
            obj.run_server()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_review()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_trust()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_history()
        except (TypeError, Exception):
            pass
        try:
            obj.build_tool_error()
        except (TypeError, Exception):
            pass
        try:
            obj.build_success_result()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:mcp_server:"), f"Bad pact_key: {key}"

